import { generateUID } from "./utils";

/**
 * 代表层
 * @class
 */
class Layer {
  /**
   * 唯一标识符
   */
  uid = generateUID();

  /**
   * 存储层中的所有图形化实例
   */
  children = [];

  /**
   * d3 包裹的 g 元素
   */
  $element;

  /**
   * @construct
   */
  constructor({ $, id }) {
    this.$element = $;
    this.$element.attr("id", id || this.uid);
  }
}

export default Layer;
